src/interfaces/IKaboomFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title IKaboomFactory
 * @notice Interface for the Kaboom token factory
 */
interface IKaboomFactory {
    /// @notice Emitted when a new token is launched
    event TokenLaunched(
        address indexed token,
        address indexed creator,
        address lpVault,
        address feeVault,
        uint256 totalSupply,
        uint256 virtualPrice,
        uint256 virtualMarketCap,
        uint256 timestamp
    );

    /// @notice Emitted when platform fee is updated
    event PlatformFeeUpdated(uint256 oldFee, uint256 newFee);

    /// @notice Emitted when platform wallet is updated
    event PlatformWalletUpdated(address oldWallet, address newWallet);

    /// @notice Custom errors
    error InvalidCreator();
    error InvalidName();
    error InvalidSymbol();
    error InvalidVaultDuration();
    error CreatorFeeExceedsMax();
    error ZeroAddress();

    /**
     * @notice Launch a new Kaboom token
     * @param name Token name
     * @param symbol Token symbol
     * @param creatorFee Creator fee in basis points (100 = 1%, max 300 = 3%)
     * @param vaultDuration Vesting duration in seconds (0, 7 days, 30 days, 180 days, 365 days)
     * @param twitterLink Optional Twitter/X link
     * @param telegramLink Optional Telegram link
     * @param websiteLink Optional website link
     * @param farcasterLink Optional Farcaster link
     * @return token Address of the deployed token
     */
    function launchToken(
        string memory name,
        string memory symbol,
        uint256 creatorFee,
        uint256 vaultDuration,
        string memory twitterLink,
        string memory telegramLink,
        string memory websiteLink,
        string memory farcasterLink
    ) external returns (address token);

    /**
     * @notice Get all tokens created by a specific creator
     * @param creator Creator address
     * @return Array of token addresses
     */
    function getTokensByCreator(address creator) external view returns (address[] memory);

    /**
     * @notice Get all launched tokens
     * @return Array of all token addresses
     */
    function getAllTokens() external view returns (address[] memory);

    /**
     * @notice Check if an address is a Kaboom token
     * @param token Token address to check
     * @return True if token was launched via Kaboom
     */
    function isKaboomToken(address token) external view returns (bool);

    /**
     * @notice Get token metadata
     * @param token Token address
     * @return creator Token creator
     * @return lpVault LP vault address
     * @return feeVault Fee vault address
     * @return virtualPrice Virtual starting price
     * @return virtualMarketCap Virtual market cap
     * @return creatorFee Creator fee in basis points
     * @return launchTime Launch timestamp
     */
    function getTokenInfo(address token) external view returns (
        address creator,
        address lpVault,
        address feeVault,
        uint256 virtualPrice,
        uint256 virtualMarketCap,
        uint256 creatorFee,
        uint256 launchTime
    );
}

src/interfaces/IKaboomFeeVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title IKaboomFeeVault
 * @notice Interface for fee collection and distribution
 */
interface IKaboomFeeVault {
    /// @notice Emitted when fees are collected
    event FeesCollected(address indexed token, uint256 platformFee, uint256 creatorFee);

    /// @notice Emitted when platform fees are claimed
    event PlatformFeesClaimed(address indexed to, uint256 amount);

    /// @notice Emitted when creator fees are claimed
    event CreatorFeesClaimed(address indexed token, address indexed to, uint256 amount);

    /// @notice Emitted when admin status is changed
    event SetAdmin(address indexed admin, bool enabled);

    /// @notice Custom errors
    error Unauthorized();
    error ZeroAddress();
    error ZeroAmount();
    error InsufficientBalance();

    /**
     * @notice Collect fees from a trade
     * @param token Token being traded
     * @param amount Total wCELO amount
     */
    function collectFees(address token, uint256 amount) external;

    /**
     * @notice Claim accumulated platform fees
     * @param to Recipient address
     */
    function claimPlatformFees(address to) external;

    /**
     * @notice Claim accumulated creator fees for a token
     * @param token Token address
     * @param to Recipient address
     */
    function claimCreatorFees(address token, address to) external;

    /**
     * @notice Set admin status for an address
     * @param admin Address to update
     * @param isAdmin Whether to grant or revoke admin
     */
    function setAdmin(address admin, bool isAdmin) external;

    /**
     * @notice Check if address is admin
     * @param account Address to check
     * @return True if admin
     */
    function isAdmin(address account) external view returns (bool);

    /**
     * @notice Get pending platform fees
     * @return Amount of unclaimed platform fees
     */
    function pendingPlatformFees() external view returns (uint256);

    /**
     * @notice Get pending creator fees for a token
     * @param token Token address
     * @return Amount of unclaimed creator fees
     */
    function pendingCreatorFees(address token) external view returns (uint256);
}

src/interfaces/IKaboomLPVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title IKaboomLPVault
 * @notice Interface for the permanent LP lock vault
 */
interface IKaboomLPVault {
    /// @notice Emitted when LP tokens are locked
    event LPLocked(address indexed token, address indexed pool, uint256 amount);

    /// @notice Custom errors
    error Unauthorized();
    error AlreadyInitialized();
    error ZeroAmount();

    /**
     * @notice Get the token this vault is for
     * @return Token address
     */
    function token() external view returns (address);

    /**
     * @notice Get the LP pool address
     * @return Pool address
     */
    function pool() external view returns (address);

    /**
     * @notice Get the factory address
     * @return Factory address
     */
    function factory() external view returns (address);

    /**
     * @notice Get locked LP token balance
     * @return Amount of LP tokens locked
     */
    function lockedBalance() external view returns (uint256);

    /**
     * @notice Check if LP is permanently locked (always true after init)
     * @return True if locked
     */
    function isLocked() external view returns (bool);
}

