src/KaboomCreatorVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

/**
 * @title KaboomCreatorVault
 * @notice Vesting vault for creator's 30% token allocation
 * @dev Supports lock periods: 0 (instant), 7 days, 30 days, 180 days, 365 days
 *      After lock period, tokens vest linearly over the same duration
 */
contract KaboomCreatorVault {
    using SafeERC20 for IERC20;

    /// @notice The Kaboom token this vault holds
    address public token;

    /// @notice The token creator (beneficiary)
    address public immutable creator;

    /// @notice The factory that deployed this vault
    address public immutable factory;

    /// @notice Vault creation timestamp
    uint256 public immutable createdAt;

    /// @notice Lock duration in seconds
    uint256 public immutable lockDuration;

    /// @notice Vesting duration in seconds (same as lock)
    uint256 public immutable vestingDuration;

    /// @notice Total tokens allocated to vault
    uint256 public immutable totalAllocation;

    /// @notice Tokens already claimed
    uint256 public claimed;

    /// @notice Whether the vault has been initialized with the token address
    bool public initialized;

    /// @notice Valid lock durations
    uint256 public constant DURATION_INSTANT = 0;
    uint256 public constant DURATION_7_DAYS = 7 days;
    uint256 public constant DURATION_30_DAYS = 30 days;
    uint256 public constant DURATION_180_DAYS = 180 days;
    uint256 public constant DURATION_365_DAYS = 365 days;

    /// @notice Emitted when tokens are claimed
    event TokensClaimed(address indexed creator, uint256 amount, uint256 totalClaimed);

    /// @notice Custom errors
    error Unauthorized();
    error NothingToClaim();
    error InvalidDuration();
    error ZeroAddress();
    error AlreadyInitialized();

    /**
     * @notice Deploy a new creator vault
     * @param token_ The Kaboom token address
     * @param creator_ The token creator address
     * @param lockDuration_ Lock period in seconds
     * @param allocation_ Total token allocation
     */
    constructor(
        address token_,
        address creator_,
        uint256 lockDuration_,
        uint256 allocation_
    ) {
        // Validate lock duration
        if (
            lockDuration_ != DURATION_INSTANT &&
            lockDuration_ != DURATION_7_DAYS &&
            lockDuration_ != DURATION_30_DAYS &&
            lockDuration_ != DURATION_180_DAYS &&
            lockDuration_ != DURATION_365_DAYS
        ) revert InvalidDuration();

        creator = creator_;
        factory = msg.sender;
        createdAt = block.timestamp;
        lockDuration = lockDuration_;
        vestingDuration = lockDuration_; // Same as lock
        totalAllocation = allocation_;
    }

    /**
     * @notice Initialize the vault with the launched token address
     * @param token_ Token address
     */
    function initialize(address token_) external {
        if (msg.sender != factory) revert Unauthorized();
        if (initialized) revert AlreadyInitialized();
        if (token_ == address(0)) revert ZeroAddress();

        token = token_;
        initialized = true;
    }

    /**
     * @notice Calculate vested amount available to claim
     * @return Amount of tokens available to claim
     */
    function vestedAmount() public view returns (uint256) {
        // If instant unlock, everything is available
        if (lockDuration == 0) {
            return totalAllocation;
        }

        uint256 elapsed = block.timestamp - createdAt;

        // Still in lock period
        if (elapsed < lockDuration) {
            return 0;
        }

        // Calculate vesting progress
        uint256 vestingElapsed = elapsed - lockDuration;

        // Fully vested
        if (vestingElapsed >= vestingDuration) {
            return totalAllocation;
        }

        // Linear vesting
        return (totalAllocation * vestingElapsed) / vestingDuration;
    }

    /**
     * @notice Get claimable amount (vested minus already claimed)
     * @return Amount available to claim now
     */
    function claimable() public view returns (uint256) {
        return vestedAmount() - claimed;
    }

    /**
     * @notice Claim vested tokens
     */
    function claim() external {
        if (msg.sender != creator) revert Unauthorized();

        uint256 amount = claimable();
        if (amount == 0) revert NothingToClaim();

        claimed += amount;
        IERC20(token).safeTransfer(creator, amount);

        emit TokensClaimed(creator, amount, claimed);
    }

    /**
     * @notice Get vault status
     * @return isLocked Whether still in lock period
     * @return lockEndsAt Timestamp when lock ends
     * @return vestingEndsAt Timestamp when fully vested
     * @return percentVested Current vesting percentage (0-100)
     */
    function getStatus() external view returns (
        bool isLocked,
        uint256 lockEndsAt,
        uint256 vestingEndsAt,
        uint256 percentVested
    ) {
        lockEndsAt = createdAt + lockDuration;
        vestingEndsAt = lockEndsAt + vestingDuration;
        isLocked = block.timestamp < lockEndsAt;
        percentVested = (vestedAmount() * 100) / totalAllocation;
    }
}

src/KaboomFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "./KaboomToken.sol";
import "./KaboomLPVault.sol";
import "./KaboomCreatorVault.sol";
import "./KaboomFeeVault.sol";
import "./interfaces/IKaboomFactory.sol";

/**
 * @title KaboomFactory
 * @notice Main factory for launching Kaboom tokens on Celo
 * @dev Deploys token + LP vault + creator vault, registers with fee vault
 */
contract KaboomFactory is IKaboomFactory {
    using SafeERC20 for IERC20;

    /// @notice wCELO token address
    address public immutable wCELO;

    /// @notice Fee vault address
    address public immutable feeVault;

    /// @notice Platform wallet
    address public platformWallet;

    /// @notice Virtual starting price: $0.0000005 (in 18 decimals)
    uint256 public constant VIRTUAL_PRICE = 5 * 10**11; // 0.0000005 * 10^18

    /// @notice Virtual market cap: $25,000 (in 18 decimals)
    uint256 public constant VIRTUAL_MARKET_CAP = 25_000 * 10**18;

    /// @notice Mapping of creator to their tokens
    mapping(address => address[]) public creatorTokens;

    /// @notice Check if address is a Kaboom token
    mapping(address => bool) public isKaboomToken;

    /// @notice All launched tokens
    address[] public allTokens;

    /// @notice Token metadata
    struct TokenInfo {
        address creator;
        address lpVault;
        address creatorVault;
        uint256 virtualPrice;
        uint256 virtualMarketCap;
        uint256 creatorFee;
        uint256 launchTime;
        string twitterLink;
        string telegramLink;
        string websiteLink;
        string farcasterLink;
    }

    /// @notice Token info mapping
    mapping(address => TokenInfo) public tokenInfo;

    /// @notice Emitted when social links are set
    event TokenMetadataSet(
        address indexed token,
        string twitterLink,
        string telegramLink,
        string websiteLink,
        string farcasterLink
    );

    /**
     * @notice Deploy the factory
     * @param wCELO_ wCELO token address
     * @param feeVault_ Fee vault address
     * @param platformWallet_ Platform wallet for fees
     */
    constructor(address wCELO_, address feeVault_, address platformWallet_) {
        if (wCELO_ == address(0)) revert ZeroAddress();
        if (feeVault_ == address(0)) revert ZeroAddress();
        if (platformWallet_ == address(0)) revert ZeroAddress();

        wCELO = wCELO_;
        feeVault = feeVault_;
        platformWallet = platformWallet_;
    }

    /**
     * @notice Launch a new Kaboom token
     * @param name Token name
     * @param symbol Token symbol
     * @param creatorFee Creator fee in basis points (100 = 1%, max 300)
     * @param vaultDuration Vesting duration (0, 7d, 30d, 180d, 365d)
     * @param twitterLink Optional Twitter link
     * @param telegramLink Optional Telegram link
     * @param websiteLink Optional website link
     * @param farcasterLink Optional Farcaster link
     * @return token Deployed token address
     */
    function launchToken(
        string memory name,
        string memory symbol,
        uint256 creatorFee,
        uint256 vaultDuration,
        string memory twitterLink,
        string memory telegramLink,
        string memory websiteLink,
        string memory farcasterLink
    ) external returns (address token) {
        // Validations
        if (bytes(name).length == 0) revert InvalidName();
        if (bytes(symbol).length == 0) revert InvalidSymbol();
        if (creatorFee > 300) revert CreatorFeeExceedsMax();

        address creator = msg.sender;

        // Deploy creator vault first (will receive 30%)
        KaboomCreatorVault creatorVault = new KaboomCreatorVault(
            address(0), // Token address set after creation
            creator,
            vaultDuration,
            (50_000_000_000 * 10**18 * 30) / 100 // 30% of 50B
        );

        // Deploy LP vault (will receive 70%)
        // Pool address will be set when first trade occurs
        KaboomLPVault lpVault = new KaboomLPVault(
            address(0), // Token address set after creation
            address(0), // Pool address set on first trade
            address(this)
        );

        // Deploy token - mints 70% to LP vault, 30% to creator vault
        KaboomToken kaboomToken = new KaboomToken(
            name,
            symbol,
            creator,
            address(lpVault),
            address(creatorVault)
        );

        token = address(kaboomToken);

        creatorVault.initialize(token);
        lpVault.initialize(token, address(0));

        // Register token with fee vault
        KaboomFeeVault(feeVault).registerToken(token, creator, creatorFee);

        // Store token info
        tokenInfo[token] = TokenInfo({
            creator: creator,
            lpVault: address(lpVault),
            creatorVault: address(creatorVault),
            virtualPrice: VIRTUAL_PRICE,
            virtualMarketCap: VIRTUAL_MARKET_CAP,
            creatorFee: creatorFee,
            launchTime: block.timestamp,
            twitterLink: twitterLink,
            telegramLink: telegramLink,
            websiteLink: websiteLink,
            farcasterLink: farcasterLink
        });

        // Register mappings
        isKaboomToken[token] = true;
        creatorTokens[creator].push(token);
        allTokens.push(token);

        emit TokenLaunched(
            token,
            creator,
            address(lpVault),
            address(creatorVault),
            50_000_000_000 * 10**18,
            VIRTUAL_PRICE,
            VIRTUAL_MARKET_CAP,
            block.timestamp
        );

        if (bytes(twitterLink).length > 0 || bytes(telegramLink).length > 0 || 
            bytes(websiteLink).length > 0 || bytes(farcasterLink).length > 0) {
            emit TokenMetadataSet(token, twitterLink, telegramLink, websiteLink, farcasterLink);
        }

        return token;
    }

    /**
     * @notice Get all tokens by a creator
     */
    function getTokensByCreator(address creator) external view returns (address[] memory) {
        return creatorTokens[creator];
    }

    /**
     * @notice Get all launched tokens
     */
    function getAllTokens() external view returns (address[] memory) {
        return allTokens;
    }

    /**
     * @notice Get token count
     */
    function getTokenCount() external view returns (uint256) {
        return allTokens.length;
    }

    /**
     * @notice Get full token info
     */
    function getTokenInfo(address token) external view returns (
        address creator,
        address lpVault,
        address feeVaultAddr,
        uint256 virtualPrice,
        uint256 virtualMarketCap,
        uint256 creatorFee,
        uint256 launchTime
    ) {
        TokenInfo memory info = tokenInfo[token];
        return (
            info.creator,
            info.lpVault,
            feeVault,
            info.virtualPrice,
            info.virtualMarketCap,
            info.creatorFee,
            info.launchTime
        );
    }

    /**
     * @notice Get token social links
     */
    function getTokenSocials(address token) external view returns (
        string memory twitterLink,
        string memory telegramLink,
        string memory websiteLink,
        string memory farcasterLink
    ) {
        TokenInfo memory info = tokenInfo[token];
        return (
            info.twitterLink,
            info.telegramLink,
            info.websiteLink,
            info.farcasterLink
        );
    }
}

src/KaboomFeeVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "./interfaces/IOwnerAdmins.sol";

/**
 * @title KaboomFeeVault
 * @notice Fee collection and distribution vault in wCELO
 * @dev Platform fee (0.4%) + Creator fee (1-3%) collected on trades
 */
contract KaboomFeeVault is IOwnerAdmins {
    using SafeERC20 for IERC20;

    /// @notice Fee token address on Celo (typically wCELO or USDC)
    address public immutable wCELO;

    /// @notice Factory address
    address public factory;

    /// @notice Platform wallet for fee claims
    address public platformWallet;

    /// @notice Platform fee in basis points (40 = 0.4%)
    uint256 public constant PLATFORM_FEE_BPS = 40;

    /// @notice Maximum creator fee in basis points (300 = 3%)
    uint256 public constant MAX_CREATOR_FEE_BPS = 300;

    /// @notice Basis points denominator
    uint256 public constant BPS_DENOMINATOR = 10000;

    /// @notice Admin mapping
    mapping(address => bool) public isAdmin;

    /// @notice Pending platform fees
    uint256 public pendingPlatformFees;

    /// @notice Pending creator fees per token
    mapping(address => uint256) public pendingCreatorFees;

    /// @notice Creator fee per token in basis points
    mapping(address => uint256) public tokenCreatorFee;

    /// @notice Token creator mapping
    mapping(address => address) public tokenCreator;

    /// @notice Emitted when fees are collected
    event FeesCollected(
        address indexed token,
        uint256 tradeAmount,
        uint256 platformFee,
        uint256 creatorFee
    );

    /// @notice Emitted when platform fees are claimed
    event PlatformFeesClaimed(address indexed to, uint256 amount);

    /// @notice Emitted when creator fees are claimed
    event CreatorFeesClaimed(address indexed token, address indexed to, uint256 amount);

    /// @notice Custom errors
    error ZeroAddress();
    error ZeroAmount();
    error InsufficientBalance();
    error InvalidCreatorFee();

    /**
     * @notice Deploy the fee vault
     * @param feeToken_ Fee token address (wCELO or USDC on Celo)
     * @param platformWallet_ Initial platform wallet
     * @param factory_ Factory address
     */
    constructor(address feeToken_, address platformWallet_, address factory_) {
        if (feeToken_ == address(0) || platformWallet_ == address(0)) revert ZeroAddress();

        wCELO = feeToken_;
        platformWallet = platformWallet_;
        factory = factory_;
        isAdmin[msg.sender] = true;
    }

    /// @notice Modifier to restrict to admins
    modifier onlyAdmin() {
        if (!isAdmin[msg.sender]) revert Unauthorized();
        _;
    }

    /// @notice Modifier to restrict to factory
    modifier onlyFactory() {
        if (msg.sender != factory) revert Unauthorized();
        _;
    }

    /**
     * @notice Register a new token with its creator fee
     * @param token Token address
     * @param creator Creator address
     * @param creatorFeeBps Creator fee in basis points
     */
    function registerToken(
        address token,
        address creator,
        uint256 creatorFeeBps
    ) external onlyFactory {
        if (creatorFeeBps > MAX_CREATOR_FEE_BPS) revert InvalidCreatorFee();

        tokenCreator[token] = creator;
        tokenCreatorFee[token] = creatorFeeBps;
    }

    /**
     * @notice Collect fees from a trade
     * @param token Token being traded
     * @param amount Total wCELO trade amount
     */
    function collectFees(address token, uint256 amount) external {
        if (amount == 0) revert ZeroAmount();

        uint256 platformFee = (amount * PLATFORM_FEE_BPS) / BPS_DENOMINATOR;
        uint256 creatorFee = (amount * tokenCreatorFee[token]) / BPS_DENOMINATOR;
        uint256 totalFee = platformFee + creatorFee;

        // Transfer fees from caller (router)
        IERC20(wCELO).safeTransferFrom(msg.sender, address(this), totalFee);

        pendingPlatformFees += platformFee;
        pendingCreatorFees[token] += creatorFee;

        emit FeesCollected(token, amount, platformFee, creatorFee);
    }

    /**
     * @notice Claim accumulated platform fees
     * @param to Recipient address
     */
    function claimPlatformFees(address to) external onlyAdmin {
        if (to == address(0)) revert ZeroAddress();

        uint256 amount = pendingPlatformFees;
        if (amount == 0) revert InsufficientBalance();

        pendingPlatformFees = 0;
        IERC20(wCELO).safeTransfer(to, amount);

        emit PlatformFeesClaimed(to, amount);
    }

    /**
     * @notice Claim accumulated creator fees for a token
     * @param token Token address
     * @param to Recipient address
     */
    function claimCreatorFees(address token, address to) external {
        // Only token creator can claim their fees
        if (msg.sender != tokenCreator[token]) revert Unauthorized();
        if (to == address(0)) revert ZeroAddress();

        uint256 amount = pendingCreatorFees[token];
        if (amount == 0) revert InsufficientBalance();

        pendingCreatorFees[token] = 0;
        IERC20(wCELO).safeTransfer(to, amount);

        emit CreatorFeesClaimed(token, to, amount);
    }

    /**
     * @notice Set admin status
     * @param admin Address to update
     * @param enabled Whether to grant or revoke
     */
    function setAdmin(address admin, bool enabled) external onlyAdmin {
        if (admin == address(0)) revert ZeroAddress();
        isAdmin[admin] = enabled;
        emit SetAdmin(admin, enabled);
    }

    /**
     * @notice Update platform wallet
     * @param newWallet New platform wallet
     */
    function setPlatformWallet(address newWallet) external onlyAdmin {
        if (newWallet == address(0)) revert ZeroAddress();
        platformWallet = newWallet;
    }

    /**
     * @notice Set factory address after deployment
     * @param newFactory New factory address
     */
    function setFactory(address newFactory) external onlyAdmin {
        if (newFactory == address(0)) revert ZeroAddress();
        factory = newFactory;
    }
}

src/KaboomLPVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

/**
 * @title KaboomLPVault
 * @notice Permanent LP lock vault - LP tokens can NEVER be withdrawn
 * @dev This ensures rug-proof liquidity for all Kaboom tokens
 */
contract KaboomLPVault {
    using SafeERC20 for IERC20;

    /// @notice The Kaboom token this vault is for
    address public token;

    /// @notice The LP pool address
    address public pool;

    /// @notice The factory that deployed this vault
    address public immutable factory;

    /// @notice Whether the vault has been initialized with LP
    bool public isLocked;

    /// @notice Whether the vault token and pool have been initialized
    bool public initialized;

    /// @notice Amount of LP tokens locked
    uint256 public lockedBalance;

    /// @notice Emitted when LP tokens are locked
    event LPLocked(address indexed token, address indexed pool, uint256 amount);

    /// @notice Custom errors
    error Unauthorized();
    error AlreadyInitialized();
    error ZeroAmount();
    error ZeroAddress();

    /**
     * @notice Deploy a new LP vault
     * @param token_ The Kaboom token address
     * @param pool_ The LP pool address
     * @param factory_ The factory address
     */
    constructor(address token_, address pool_, address factory_) {
        token = token_;
        pool = pool_;
        factory = factory_;
    }

    /**
     * @notice Initialize token and pool addresses after deployment
     * @param token_ Token address
     * @param pool_ Pool address
     */
    function initialize(address token_, address pool_) external {
        if (msg.sender != factory) revert Unauthorized();
        if (initialized) revert AlreadyInitialized();
        if (token_ == address(0)) revert ZeroAddress();

        token = token_;
        pool = pool_;
        initialized = true;
    }

    /**
     * @notice Lock LP tokens permanently
     * @dev Can only be called once by the factory
     * @param amount Amount of LP tokens to lock
     */
    function lockLP(uint256 amount) external {
        if (msg.sender != factory) revert Unauthorized();
        if (isLocked) revert AlreadyInitialized();
        if (amount == 0) revert ZeroAmount();

        isLocked = true;
        lockedBalance = amount;

        // Transfer LP tokens to this vault (they stay here forever)
        IERC20(pool).safeTransferFrom(msg.sender, address(this), amount);

        emit LPLocked(token, pool, amount);
    }

    /**
     * @notice Get the current LP balance (should equal lockedBalance)
     * @return Current LP token balance
     */
    function getLPBalance() external view returns (uint256) {
        return IERC20(pool).balanceOf(address(this));
    }

    // No withdraw functions - LP is permanently locked
}

src/KaboomRouter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./interfaces/IKaboomFactory.sol";
import "./KaboomFeeVault.sol";

/**
 * @title KaboomRouter
 * @notice Router for buying/selling Kaboom tokens with automatic fee collection
 * @dev Handles trades and emits events for chart indexing
 */
contract KaboomRouter is ReentrancyGuard {
    using SafeERC20 for IERC20;

    /// @notice Factory address
    address public immutable factory;

    /// @notice Fee vault address
    address public immutable feeVault;

    /// @notice wCELO address
    address public immutable wCELO;

    /// @notice AMM pool interface (simplified - integrate with Ubeswap/Curve)
    /// In production, this would integrate with actual DEX

    /// @notice Emitted on every trade (for chart indexing)
    event Trade(
        address indexed token,
        address indexed trader,
        bool isBuy,
        uint256 amountIn,
        uint256 amountOut,
        uint256 price,
        uint256 timestamp
    );

    /// @notice Emitted when pool is initialized on first buy
    event PoolInitialized(
        address indexed token,
        address indexed pool,
        uint256 initialLiquidity,
        uint256 timestamp
    );

    /// @notice Custom errors
    error InvalidToken();
    error InsufficientOutput();
    error ZeroAmount();
    error SlippageExceeded();

    /**
     * @notice Deploy the router
     * @param factory_ Factory address
     * @param feeVault_ Fee vault address
     * @param wCELO_ wCELO address
     */
    constructor(address factory_, address feeVault_, address wCELO_) {
        factory = factory_;
        feeVault = feeVault_;
        wCELO = wCELO_;
    }

    /**
     * @notice Buy Kaboom tokens with wCELO
     * @param token Token to buy
     * @param amountIn Amount of wCELO to spend
     * @param minAmountOut Minimum tokens to receive
     * @return amountOut Actual tokens received
     */
    function buy(
        address token,
        uint256 amountIn,
        uint256 minAmountOut
    ) external nonReentrant returns (uint256 amountOut) {
        if (!IKaboomFactory(factory).isKaboomToken(token)) revert InvalidToken();
        if (amountIn == 0) revert ZeroAmount();

        // Transfer wCELO from user
        IERC20(wCELO).safeTransferFrom(msg.sender, address(this), amountIn);

        // Collect fees (platform + creator)
        IERC20(wCELO).approve(feeVault, amountIn);
        KaboomFeeVault(feeVault).collectFees(token, amountIn);

        // Calculate amount after fees
        uint256 platformFee = (amountIn * 40) / 10000; // 0.4%
        (,,,,,uint256 creatorFeeBps,) = IKaboomFactory(factory).getTokenInfo(token);
        uint256 creatorFee = (amountIn * creatorFeeBps) / 10000;
        uint256 amountAfterFees = amountIn - platformFee - creatorFee;

        // Execute swap on AMM (simplified - integrate with actual DEX)
        // In production: call Ubeswap/Curve router
        amountOut = _executeSwap(token, amountAfterFees, true);

        if (amountOut < minAmountOut) revert SlippageExceeded();

        // Transfer tokens to buyer
        IERC20(token).safeTransfer(msg.sender, amountOut);

        // Get current price for event
        uint256 price = _getCurrentPrice(token);

        emit Trade(token, msg.sender, true, amountIn, amountOut, price, block.timestamp);

        return amountOut;
    }

    /**
     * @notice Sell Kaboom tokens for wCELO
     * @param token Token to sell
     * @param amountIn Amount of tokens to sell
     * @param minAmountOut Minimum wCELO to receive
     * @return amountOut Actual wCELO received
     */
    function sell(
        address token,
        uint256 amountIn,
        uint256 minAmountOut
    ) external nonReentrant returns (uint256 amountOut) {
        if (!IKaboomFactory(factory).isKaboomToken(token)) revert InvalidToken();
        if (amountIn == 0) revert ZeroAmount();

        // Transfer tokens from user
        IERC20(token).safeTransferFrom(msg.sender, address(this), amountIn);

        // Execute swap on AMM
        uint256 grossAmountOut = _executeSwap(token, amountIn, false);

        // Collect fees from output
        IERC20(wCELO).approve(feeVault, grossAmountOut);
        KaboomFeeVault(feeVault).collectFees(token, grossAmountOut);

        // Calculate amount after fees
        uint256 platformFee = (grossAmountOut * 40) / 10000;
        (,,,,,uint256 creatorFeeBps,) = IKaboomFactory(factory).getTokenInfo(token);
        uint256 creatorFee = (grossAmountOut * creatorFeeBps) / 10000;
        amountOut = grossAmountOut - platformFee - creatorFee;

        if (amountOut < minAmountOut) revert SlippageExceeded();

        // Transfer wCELO to seller
        IERC20(wCELO).safeTransfer(msg.sender, amountOut);

        // Get current price for event
        uint256 price = _getCurrentPrice(token);

        emit Trade(token, msg.sender, false, amountIn, amountOut, price, block.timestamp);

        return amountOut;
    }

    /**
     * @notice Get quote for buying tokens
     * @param token Token to buy
     * @param amountIn wCELO amount
     * @return amountOut Expected token amount
     * @return priceImpact Price impact in basis points
     */
    function getBuyQuote(
        address token,
        uint256 amountIn
    ) external view returns (uint256 amountOut, uint256 priceImpact) {
        // Calculate fees
        uint256 platformFee = (amountIn * 40) / 10000;
        (,,,,,uint256 creatorFeeBps,) = IKaboomFactory(factory).getTokenInfo(token);
        uint256 creatorFee = (amountIn * creatorFeeBps) / 10000;
        uint256 amountAfterFees = amountIn - platformFee - creatorFee;

        // Get quote from AMM (simplified)
        amountOut = _getSwapQuote(token, amountAfterFees, true);
        priceImpact = _calculatePriceImpact(token, amountIn, true);

        return (amountOut, priceImpact);
    }

    /**
     * @notice Get quote for selling tokens
     * @param token Token to sell
     * @param amountIn Token amount
     * @return amountOut Expected wCELO amount
     * @return priceImpact Price impact in basis points
     */
    function getSellQuote(
        address token,
        uint256 amountIn
    ) external view returns (uint256 amountOut, uint256 priceImpact) {
        // Get gross output from AMM
        uint256 grossAmountOut = _getSwapQuote(token, amountIn, false);

        // Calculate fees
        uint256 platformFee = (grossAmountOut * 40) / 10000;
        (,,,,,uint256 creatorFeeBps,) = IKaboomFactory(factory).getTokenInfo(token);
        uint256 creatorFee = (grossAmountOut * creatorFeeBps) / 10000;
        amountOut = grossAmountOut - platformFee - creatorFee;

        priceImpact = _calculatePriceImpact(token, amountIn, false);

        return (amountOut, priceImpact);
    }

    // ============ Internal Functions ============

    /**
     * @dev Execute swap on AMM - PLACEHOLDER
     * In production, integrate with Ubeswap/Curve
     */
    function _executeSwap(
        address token,
        uint256 amountIn,
        bool isBuy
    ) internal returns (uint256) {
        // TODO: Integrate with actual DEX
        // This is a placeholder - returns simplified calculation
        if (isBuy) {
            // wCELO -> Token
            return amountIn * 1000; // Simplified
        } else {
            // Token -> wCELO
            return amountIn / 1000; // Simplified
        }
    }

    /**
     * @dev Get swap quote from AMM - PLACEHOLDER
     */
    function _getSwapQuote(
        address token,
        uint256 amountIn,
        bool isBuy
    ) internal view returns (uint256) {
        // TODO: Get actual quote from DEX
        if (isBuy) {
            return amountIn * 1000;
        } else {
            return amountIn / 1000;
        }
    }

    /**
     * @dev Get current token price - PLACEHOLDER
     */
    function _getCurrentPrice(address token) internal view returns (uint256) {
        // TODO: Get price from DEX pool
        // Return virtual price as fallback
        (,,,uint256 virtualPrice,,,) = IKaboomFactory(factory).getTokenInfo(token);
        return virtualPrice;
    }

    /**
     * @dev Calculate price impact - PLACEHOLDER
     */
    function _calculatePriceImpact(
        address token,
        uint256 amountIn,
        bool isBuy
    ) internal view returns (uint256) {
        // TODO: Calculate actual price impact from pool reserves
        // Simplified: larger trades = more impact
        return (amountIn / 10**18) * 10; // 0.1% per 1 wCELO
    }
